## `emit(event)`

Emits a custom event. The `instrumentId` is added automatically.

```ts
api.emit({
  event: "item.selected",     // Event name
  payload: { itemId: "123" }, // Arbitrary data (optional)
});
```

Received by all `instrument.event` subscribers across all panels and instruments.

Most real instruments use two panels: a **sidebar** for navigation and a **second panel** for details. This tutorial shows how to wire them together.

## The pattern

Since each panel is a separate React tree (they run in independent mount points), they can't share React state directly. Instead, use this flow:

1. **Write** the selected item ID to `storage.setProperty()`
2. **Emit** a custom event with `api.emit()`
3. The other panel **subscribes** to `instrument.event` with `useHostEvent()`
4. On receiving the event, it **reads** the selected ID and loads detail data

## Manifest

Enable both sidebar and second panels in `package.json`:

```json
{
  "tango": {
    "instrument": {
      "panels": {
        "sidebar": true,
        "first": false,
        "second": true,
        "right": false
      },
      "permissions": ["storage.properties"]
    }
  }
}
```

## Shared types

Define shared types at the top of your `src/index.tsx`:

```tsx
type Item = {
  id: string;
  name: string;
  description: string;
};

const ITEMS: Item[] = [
  { id: "1", name: "Alpha", description: "First item with details" },
  { id: "2", name: "Beta", description: "Second item with details" },
  { id: "3", name: "Gamma", description: "Third item with details" },
];

const SELECTED_KEY = "__ui_selectedItemId";
```

## Sidebar panel — the list

The sidebar shows items and writes the selection to storage + emits an event:

```tsx
import { useCallback, useEffect, useRef, useState } from "react";
import {
  defineReactInstrument, useInstrumentApi, useHostEvent,
  UIRoot, UIPanelHeader, UISection,
  UIGroupList, UIGroupItem, UIBadge,
} from "@tango/api";

function SidebarPanel() {
  const api = useInstrumentApi();
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Restore persisted selection on mount
  const initialized = useRef(false);
  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;
    api.storage.getProperty<string>(SELECTED_KEY).then((id) => {
      if (id) setSelectedId(id);
    });
  }, [api]);

  const selectItem = useCallback((id: string) => {
    setSelectedId(id);
    // Persist so the other panel can read it
    api.storage.setProperty(SELECTED_KEY, id);
    // Notify the other panel
    api.emit({ event: "item.selected", payload: { itemId: id } });
  }, [api]);

  // Listen for selection changes from the other panel (if it can select too)
  useHostEvent("instrument.event", useCallback((payload) => {
    if (payload.instrumentId !== api.instrumentId) return;
    if (payload.event === "item.selected") {
      const itemId = String((payload.payload as any)?.itemId ?? "");
      if (itemId) setSelectedId(itemId);
    }
  }, [api]));

  return (
    <UIRoot>
      <UIPanelHeader
        title="Items"
        rightActions={<UIBadge label={`${ITEMS.length}`} tone="info" />}
      />
      <UISection>
        <UIGroupList>
          {ITEMS.map((item) => (
            <UIGroupItem
              key={item.id}
              title={item.name}
              subtitle={item.description}
              active={item.id === selectedId}
              onClick={() => selectItem(item.id)}
            />
          ))}
        </UIGroupList>
      </UISection>
    </UIRoot>
  );
}
```

## Second panel — the detail view

The second panel reads the persisted selection on mount, then listens for changes:

```tsx
function SecondPanel() {
  const api = useInstrumentApi();
  const [item, setItem] = useState<Item | null>(null);

  // Restore persisted selection on mount
  const initialized = useRef(false);
  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;
    api.storage.getProperty<string>(SELECTED_KEY).then((id) => {
      if (id) setItem(ITEMS.find((i) => i.id === id) ?? null);
    });
  }, [api]);

  // Listen for selection events from the sidebar
  useHostEvent("instrument.event", useCallback((payload) => {
    if (payload.instrumentId !== api.instrumentId) return;
    if (payload.event === "item.selected") {
      const itemId = String((payload.payload as any)?.itemId ?? "");
      const found = ITEMS.find((i) => i.id === itemId);
      setItem(found ?? null);
    }
  }, [api]));

  return (
    <UIRoot>
      <UIPanelHeader
        title={item?.name ?? "Item Detail"}
        subtitle={item ? `ID: ${item.id}` : "Select an item from the sidebar"}
      />
      <UISection>
        {item ? (
          <UICard>
            <p>{item.description}</p>
          </UICard>
        ) : (
          <UIEmptyState
            title="No item selected"
            description="Click an item in the sidebar to see its details here."
          />
        )}
      </UISection>
    </UIRoot>
  );
}
```

## Wire it up

```tsx
export default defineReactInstrument({
  defaults: {
    visible: { sidebar: true, second: true },
  },
  panels: {
    sidebar: SidebarPanel,
    second: SecondPanel,
  },
});
```

## How it works

```
┌─────────────┐                    ┌──────────────┐
│   Sidebar    │                    │  Second Panel │
│              │                    │               │
│  selectItem  │                    │               │
│      │       │                    │               │
│      ├───── storage.setProperty ──┤               │
│      │       │                    │               │
│      └───── api.emit ─────────── useHostEvent ──► │
│              │                    │   setItem()   │
└─────────────┘                    └──────────────┘
```

1. User clicks an item in the sidebar
2. `storage.setProperty` persists the selection (survives page reloads)
3. `api.emit` sends a real-time event
4. The second panel's `useHostEvent` handler receives it and updates its state

:::caution[Filtering is manual]
The `instrument.event` handler receives events from **all** instruments. You must check `payload.instrumentId === api.instrumentId` to filter events meant for your instrument.
:::

## Next steps

Your panels are communicating, but all data is hardcoded. In the [next tutorial](/tutorials/04-backend-actions/) you'll move logic to a backend and call it from the frontend.

Backend actions run in the host Bun process — outside the browser sandbox. Use them for file system access, network requests, heavy computation, or anything that doesn't belong in the frontend.

## Add a backend entry point

Update your manifest in `package.json`:

```json
{
  "tango": {
    "instrument": {
      "backendEntrypoint": "./dist/backend.js"
    }
  }
}
```

## Define the backend

Create `src/backend.ts`:

```ts
import { defineBackend, type InstrumentBackendContext } from "@tango/api/backend";

export default defineBackend({
  kind: "tango.instrument.backend.v2",
  actions: {
    greet: {
      input: {
        type: "object",
        properties: {
          name: { type: "string" },
        },
      },
      output: {
        type: "object",
        properties: {
          greeting: { type: "string" },
          timestamp: { type: "number" },
        },
        required: ["greeting", "timestamp"],
      },
      handler: async (ctx, input) => {
        const name = (input as { name?: string })?.name ?? "world";
        return {
          greeting: `Hello, ${name}!`,
          timestamp: Date.now(),
        };
      },
    },
  },
});
```

### Anatomy of an action

Each action has three parts:

| Part | Required | Description |
|------|----------|-------------|
| `input` | No | JSON schema describing the expected input |
| `output` | No | JSON schema describing the return value |
| `handler` | Yes | Async function `(ctx, input) => output` |

### The context object

Every handler receives an `InstrumentBackendContext` as its first argument:

```ts
type InstrumentBackendContext = {
  instrumentId: string;
  permissions: InstrumentPermission[];
  emit: (event: { event: string; payload?: unknown }) => void;
  host: {
    storage: StorageAPI;
    sessions: SessionsAPI;
    connectors: ConnectorsAPI;
    stages: StageAPI;
    events: HostEventsAPI;
    settings: InstrumentSettingsAPI;
  };
};
```

You have full access to the same APIs as the frontend, plus the ability to emit events back to the UI.

## Call from the frontend

Use `useInstrumentAction` to create a typed caller:

```tsx
import { useInstrumentAction, useInstrumentApi, UIRoot, UIPanelHeader, UISection, UICard, UIButton, UIInput } from "@tango/api";
import { useState } from "react";

type GreetInput = { name: string };
type GreetOutput = { greeting: string; timestamp: number };

function SidebarPanel() {
  const api = useInstrumentApi();
  const greet = useInstrumentAction<GreetInput, GreetOutput>("greet");
  const [name, setName] = useState("");
  const [result, setResult] = useState<GreetOutput | null>(null);

  const handleGreet = async () => {
    const output = await greet({ name });
    setResult(output);
  };

  return (
    <UIRoot>
      <UIPanelHeader title="Greeter" />
      <UISection>
        <UICard>
          <UIInput value={name} placeholder="Your name" onInput={setName} />
          <UIButton label="Greet" variant="primary" onClick={handleGreet} />
          {result && <p>{result.greeting} (at {new Date(result.timestamp).toLocaleTimeString()})</p>}
        </UICard>
      </UISection>
    </UIRoot>
  );
}
```

### How `useInstrumentAction` works

```tsx
const greet = useInstrumentAction<TInput, TOutput>("greet");
// Returns: (input?: TInput) => Promise<TOutput>
```

It's a thin wrapper around `api.actions.call("greet", input)` that is stable across re-renders (uses `useCallback` internally).

## Lifecycle hooks

The backend supports `onStart` and `onStop`:

```ts
export default defineBackend({
  kind: "tango.instrument.backend.v2",
  actions: { /* ... */ },
  onStart: async (ctx) => {
    // Runs when the instrument loads
    console.log(`Backend started for ${ctx.instrumentId}`);
  },
  onStop: async () => {
    // Runs when the instrument unloads
    console.log("Backend stopped");
  },
});
```

## Emitting events from the backend

Backend actions can push updates to the frontend:

```ts
handler: async (ctx, input) => {
  // Do some work...
  ctx.emit({ event: "task.completed", payload: { taskId: "123" } });
  return { success: true };
},
```

The frontend receives this via `useHostEvent("instrument.event", handler)`.

## Input schemas

The `ActionSchema` type supports these JSON schema types:

```ts
type ActionSchema =
  | { type: "any" }
  | { type: "null" }
  | { type: "string" }
  | { type: "number" }
  | { type: "boolean" }
  | { type: "array"; items?: ActionSchema }
  | {
      type: "object";
      properties?: Record<string, ActionSchema>;
      required?: string[];
      additionalProperties?: boolean;
    };
```

Schemas are optional but recommended — they serve as documentation and will enable validation in future SDK versions.

## Next steps

Backend actions are great for logic, but you also need persistent data. In the [next tutorial](/tutorials/05-storage/) you'll learn about the three storage tiers.

The SDK provides three storage tiers. Each is available on both the frontend (`api.storage`) and the backend (`ctx.host.storage`). All data is scoped per-instrument — instruments cannot access each other's storage.

## Tier 1: Key-value properties

The simplest option. Store and retrieve JSON-serializable values by key.

**Permission required**: `storage.properties`

```tsx
// Write
await api.storage.setProperty("lastOpenedTab", "settings");
await api.storage.setProperty("counter", 42);
await api.storage.setProperty("config", { theme: "dark", fontSize: 14 });

// Read
const tab = await api.storage.getProperty<string>("lastOpenedTab");       // "settings"
const count = await api.storage.getProperty<number>("counter");           // 42
const config = await api.storage.getProperty<{ theme: string }>("config"); // { theme: "dark", ... }

// Delete
await api.storage.deleteProperty("counter");

// Returns null for missing keys
const missing = await api.storage.getProperty("nonexistent"); // null
```

### When to use properties

- UI state that should survive reloads (selected tab, scroll position, collapsed sections)
- Small configuration values
- Cross-panel state synchronization (as seen in [Tutorial 3](/tutorials/03-multiple-panels/))

## Tier 2: File storage

Read and write files in a sandboxed directory. Useful for larger blobs, exports, or imported data.

**Permission required**: `storage.files`

```tsx
// Write a text file
await api.storage.writeFile("notes/meeting.md", "# Meeting Notes\n\n- Item 1\n- Item 2");

// Read it back
const content = await api.storage.readFile("notes/meeting.md"); // string

// Write binary data (base64)
await api.storage.writeFile("images/logo.png", base64String, "base64");

// Read binary data
const b64 = await api.storage.readFile("images/logo.png", "base64");

// List files in a directory
const files = await api.storage.listFiles("notes/"); // ["notes/meeting.md"]

// List all files
const allFiles = await api.storage.listFiles(); // ["notes/meeting.md", "images/logo.png"]

// Delete a file
await api.storage.deleteFile("notes/meeting.md");
```

### When to use files

- Markdown documents, JSON exports, CSV data
- Binary content (images, PDFs)
- Anything too large for a property value
- Data you want to organize in a directory structure

## Tier 3: SQLite

Full relational database. Each instrument gets its own SQLite database (or multiple named databases).

**Permission required**: `storage.db`

### Create tables

```tsx
await api.storage.sqlExecute(`
  CREATE TABLE IF NOT EXISTS tasks (
    id TEXT PRIMARY KEY,
    title TEXT NOT NULL,
    status TEXT DEFAULT 'todo',
    created_at TEXT DEFAULT (datetime('now'))
  )
`);
```

### Insert data

```tsx
await api.storage.sqlExecute(
  "INSERT INTO tasks (id, title, status) VALUES (?, ?, ?)",
  ["task-1", "Build docs", "in_progress"]
);
```

### Query data

```tsx
type Task = { id: string; title: string; status: string; created_at: string };

const tasks = await api.storage.sqlQuery<Task>(
  "SELECT * FROM tasks WHERE status = ? ORDER BY created_at DESC",
  ["todo"]
);
// tasks: Task[]
```

### Update and delete

```tsx
const result = await api.storage.sqlExecute(
  "UPDATE tasks SET status = ? WHERE id = ?",
  ["done", "task-1"]
);
// result: { changes: 1, lastInsertRowid: null }

await api.storage.sqlExecute("DELETE FROM tasks WHERE id = ?", ["task-1"]);
```

### Multiple databases

Pass a database name as the third argument:

```tsx
// Uses a separate "analytics" database
await api.storage.sqlExecute(
  "CREATE TABLE IF NOT EXISTS events (id TEXT, type TEXT, timestamp TEXT)",
  [],
  "analytics"
);

await api.storage.sqlQuery("SELECT * FROM events", [], "analytics");
```

### When to use SQLite

- Structured data with relationships
- Data you need to query/filter/sort
- Large datasets (thousands of records)
- When you need transactions or constraints

## Complete example

Here's a sidebar that uses all three tiers:

```tsx
import { useEffect, useState } from "react";
import {
  defineReactInstrument, useInstrumentApi,
  UIRoot, UIPanelHeader, UISection, UICard,
  UIButton, UIInput, UIBadge,
} from "@tango/api";

type Note = { id: string; title: string; created_at: string };

function SidebarPanel() {
  const api = useInstrumentApi();
  const [notes, setNotes] = useState<Note[]>([]);
  const [title, setTitle] = useState("");
  const [viewCount, setViewCount] = useState(0);

  useEffect(() => {
    // Initialize SQLite table
    api.storage.sqlExecute(`
      CREATE TABLE IF NOT EXISTS notes (
        id TEXT PRIMARY KEY,
        title TEXT NOT NULL,
        created_at TEXT DEFAULT (datetime('now'))
      )
    `).then(() => loadNotes());

    // Track page views with properties
    api.storage.getProperty<number>("viewCount").then((count) => {
      const next = (count ?? 0) + 1;
      setViewCount(next);
      api.storage.setProperty("viewCount", next);
    });
  }, [api]);

  const loadNotes = async () => {
    const rows = await api.storage.sqlQuery<Note>("SELECT * FROM notes ORDER BY created_at DESC");
    setNotes(rows);
  };

  const addNote = async () => {
    if (!title.trim()) return;
    const id = crypto.randomUUID();
    await api.storage.sqlExecute(
      "INSERT INTO notes (id, title) VALUES (?, ?)",
      [id, title]
    );
    // Also save as a markdown file
    await api.storage.writeFile(`notes/${id}.md`, `# ${title}\n\nCreated: ${new Date().toISOString()}`);
    setTitle("");
    await loadNotes();
  };

  return (
    <UIRoot>
      <UIPanelHeader
        title="Notes"
        rightActions={<UIBadge label={`${viewCount} views`} tone="neutral" />}
      />
      <UISection>
        <UICard>
          <UIInput value={title} placeholder="New note title" onInput={setTitle} />
          <UIButton label="Add Note" variant="primary" onClick={addNote} />
        </UICard>
      </UISection>
      <UISection title={`${notes.length} notes`}>
        {notes.map((note) => (
          <UICard key={note.id}>
            <strong>{note.title}</strong>
            <small>{note.created_at}</small>
          </UICard>
        ))}
      </UISection>
    </UIRoot>
  );
}

export default defineReactInstrument({
  defaults: { visible: { sidebar: true } },
  panels: { sidebar: SidebarPanel },
});
```

## Next steps

You can persist data, but you're not yet reacting to what's happening in Tango. In the [next tutorial](/tutorials/06-events-and-hooks/) you'll subscribe to host events like session streams and stage changes.

Tango's event system lets instruments react to changes in the host app — new sessions starting, stream output, stage changes, tool approvals, and more.

## useHostEvent

The primary way to subscribe to events in React:

```tsx
import { useHostEvent } from "@tango/api";

useHostEvent("snapshot.update", (snapshot) => {
  console.log("Processes:", snapshot.processes.length);
  console.log("Tasks:", snapshot.tasks.length);
});
```

The hook automatically subscribes on mount and unsubscribes on unmount. The `handler` should be wrapped in `useCallback` to avoid unnecessary resubscriptions:

```tsx
import { useCallback } from "react";

useHostEvent("session.ended", useCallback((payload) => {
  console.log(`Session ${payload.sessionId} ended with code ${payload.exitCode}`);
}, []));
```

## All host events

### `snapshot.update`

Fires periodically with the current state of all Claude processes and tasks.

```tsx
useHostEvent("snapshot.update", useCallback((snapshot) => {
  // snapshot.processes — running Claude processes
  // snapshot.tasks — active tasks
  // snapshot.subagents — spawned subagents
  // snapshot.eventCount — total events processed
}, []));
```

### `session.stream`

Fires for every stream event from a Claude session. This is the raw output stream.

```tsx
useHostEvent("session.stream", useCallback((payload) => {
  const { sessionId, event } = payload;
  // event is a ClaudeStreamEvent — contains assistant messages, tool calls, etc.
}, []));
```

### `session.idResolved`

Fires when a temporary session ID is replaced with the real one (happens right after session spawn).

```tsx
useHostEvent("session.idResolved", useCallback((payload) => {
  console.log(`${payload.tempId} → ${payload.realId}`);
}, []));
```

### `session.ended`

Fires when a Claude session terminates.

```tsx
useHostEvent("session.ended", useCallback((payload) => {
  console.log(`Session ${payload.sessionId} exited with code ${payload.exitCode}`);
}, []));
```

### `tool.approval`

Fires when Claude wants to use a tool and is waiting for user approval.

```tsx
useHostEvent("tool.approval", useCallback((approval) => {
  // approval: ToolApprovalRequest
  // Contains tool name, arguments, session info
}, []));
```

### `instrument.event`

Fires when any instrument emits a custom event. This is the inter-panel and inter-instrument communication channel.

```tsx
useHostEvent("instrument.event", useCallback((payload) => {
  // payload.instrumentId — which instrument emitted this
  // payload.event — event name (e.g. "item.selected")
  // payload.payload — arbitrary data
  if (payload.instrumentId !== api.instrumentId) return;
  if (payload.event === "item.selected") {
    // handle it
  }
}, [api]));
```

:::caution
Always filter by `payload.instrumentId` — you'll receive events from all instruments, not just your own.
:::

### `stage.added`

Fires when the user opens a new stage (project folder).

```tsx
useHostEvent("stage.added", useCallback((payload) => {
  console.log(`New stage: ${payload.path}`);
}, []));
```

### `stage.removed`

Fires when a stage is removed.

```tsx
useHostEvent("stage.removed", useCallback((payload) => {
  console.log(`Stage removed: ${payload.path}`);
}, []));
```

### `connector.auth.changed`

Fires when a connector's authorization state changes.

```tsx
useHostEvent("connector.auth.changed", useCallback((session) => {
  // session: ConnectorAuthSession
}, []));
```

### `pullRequest.agentReviewChanged`

Fires when an agent-driven PR review changes status.

```tsx
useHostEvent("pullRequest.agentReviewChanged", useCallback((payload) => {
  console.log(`PR #${payload.number} review: ${payload.status}`);
  // status: "running" | "completed" | "failed" | "stale"
}, []));
```

## Emitting custom events

Use `api.emit()` to send events that other panels (or other instruments) can receive:

```tsx
const api = useInstrumentApi();

// Emit a custom event
api.emit({
  event: "item.selected",
  payload: { itemId: "abc-123" },
});
```

The event is delivered as an `instrument.event` to all subscribers. The `instrumentId` field is added automatically.

## Backend event emission

Backend actions can also emit events:

```ts
// In backend.ts
handler: async (ctx, input) => {
  // ... do work ...
  ctx.emit({
    event: "processing.complete",
    payload: { resultCount: 42 },
  });
  return { success: true };
},
```

## Events API (non-React)

If you're not using React, use the events API directly:

```ts
// Subscribe — returns an unsubscribe function
const unsubscribe = api.events.subscribe("snapshot.update", (snapshot) => {
  console.log(snapshot.processes.length, "processes");
});

// Later: unsubscribe
unsubscribe();
```

## Practical example: Live session monitor

Here's a complete instrument that monitors active sessions in real time:

```tsx
import { useCallback, useState } from "react";
import {
  defineReactInstrument, useInstrumentApi, useHostEvent,
  UIRoot, UIPanelHeader, UISection, UICard,
  UIBadge, UIGroupList, UIGroupItem, UIEmptyState,
} from "@tango/api";

type SessionLog = {
  sessionId: string;
  status: "active" | "ended";
  exitCode?: number;
};

function SidebarPanel() {
  const api = useInstrumentApi();
  const [sessions, setSessions] = useState<Map<string, SessionLog>>(new Map());

  // Track session starts from snapshots
  useHostEvent("snapshot.update", useCallback((snapshot) => {
    setSessions((prev) => {
      const next = new Map(prev);
      for (const task of snapshot.tasks) {
        if (task.sessionId && !next.has(task.sessionId)) {
          next.set(task.sessionId, {
            sessionId: task.sessionId,
            status: "active",
          });
        }
      }
      return next;
    });
  }, []));

  // Track session ends
  useHostEvent("session.ended", useCallback((payload) => {
    setSessions((prev) => {
      const next = new Map(prev);
      next.set(payload.sessionId, {
        sessionId: payload.sessionId,
        status: "ended",
        exitCode: payload.exitCode,
      });
      return next;
    });
  }, []));

  const sessionList = Array.from(sessions.values());

  return (
    <UIRoot>
      <UIPanelHeader
        title="Session Monitor"
        rightActions={
          <UIBadge
            label={`${sessionList.filter((s) => s.status === "active").length} active`}
            tone="info"
          />
        }
      />
      <UISection>
        {sessionList.length === 0 ? (
          <UIEmptyState title="No sessions" description="Sessions will appear here as they start." />
        ) : (
          <UIGroupList>
            {sessionList.map((session) => (
              <UIGroupItem
                key={session.sessionId}
                title={session.sessionId.slice(0, 8)}
                subtitle={session.status}
                meta={
                  <UIBadge
                    label={session.status}
                    tone={session.status === "active" ? "success" : "neutral"}
                  />
                }
              />
            ))}
          </UIGroupList>
        )}
      </UISection>
    </UIRoot>
  );
}

export default defineReactInstrument({
  defaults: { visible: { sidebar: true } },
  panels: { sidebar: SidebarPanel },
});
```

## Summary

| Event | Fires when |
|-------|-----------|
| `snapshot.update` | Periodically, with all process/task state |
| `session.stream` | Each stream chunk from a Claude session |
| `session.idResolved` | Temp ID → real ID mapping is known |
| `session.ended` | A session terminates |
| `tool.approval` | Claude requests tool permission |
| `instrument.event` | Any instrument emits a custom event |
| `stage.added` | User opens a stage |
| `stage.removed` | A stage is removed |
| `connector.auth.changed` | Connector auth state changes |
| `pullRequest.agentReviewChanged` | PR review status changes |

